import React from 'react';
import { Link } from 'react-router-dom';
import StarField from '../components/StarField';
import Book from '../components/Book';
import { useBook } from '../context/BookContext';

export default function ReaderPage() {
  const { book } = useBook();

  return (
    <div className="reader-page">
      <style>{`
        .reader-page {
          min-height:100vh;
          background:var(--space);
          display:flex; flex-direction:column;
          align-items:center; justify-content:center;
          padding:20px;
          position:relative;
          overflow:hidden;
        }
        .reader-page::before {
          content:'';
          position:fixed; inset:0;
          background:
            radial-gradient(ellipse 65% 45% at 18% 50%, rgba(80,30,160,.16) 0%, transparent 70%),
            radial-gradient(ellipse 65% 45% at 82% 50%, rgba(20,80,180,.13) 0%, transparent 70%);
          pointer-events:none; z-index:0;
        }
        .reader-header {
          position:relative; z-index:10;
          display:flex; align-items:center; justify-content:space-between;
          width:min(860px,95vw); margin-bottom:28px;
        }
        .reader-logo {
          font-family:'Cinzel',serif;
          font-size:clamp(11px,1.6vw,15px);
          letter-spacing:.3em; color:rgba(240,192,64,.55);
          text-decoration:none; text-transform:uppercase;
        }
        .reader-logo:hover { color:rgba(240,192,64,.9); }
        .admin-link {
          font-family:'Cinzel',serif;
          font-size:clamp(9px,1.2vw,11px);
          letter-spacing:.25em; color:rgba(255,255,255,.2);
          text-decoration:none; text-transform:uppercase;
          padding:6px 16px; border:1px solid rgba(255,255,255,.1);
          border-radius:4px; transition:all .2s;
          display:flex; align-items:center; gap:8px;
        }
        .admin-link:hover {
          color:rgba(255,255,255,.6); border-color:rgba(255,255,255,.25);
          background:rgba(255,255,255,.04);
        }
        .admin-link-dot {
          width:6px; height:6px; border-radius:50%;
          background:var(--admin-accent); opacity:.6;
          animation:adpulse 2s ease-in-out infinite;
        }
        @keyframes adpulse { 0%,100%{opacity:.4} 50%{opacity:1} }
      `}</style>

      <StarField count={90} />

      <header className="reader-header">
        <span className="reader-logo">✦ Cosmic Reader</span>
        <Link to="/admin" className="admin-link">
          <span className="admin-link-dot" />
          Admin Panel
        </Link>
      </header>

      <Book book={book} />
    </div>
  );
}
